const body = $input.first().json;
const eng = body.engagement ?? body;

return [{
  json: {
    clientName:   eng.clientName,
    company:      eng.company,
    serviceType:  eng.serviceType,
    owner:        eng.owner,
    email:        eng.email,
    startDate:    eng.startDate,
    status:       eng.status,
    slackMessage: `🆕 New engagement created\n*Client:* ${eng.clientName} — ${eng.company}\n*Service:* ${eng.serviceType}\n*Owner:* ${eng.owner}\n*Start date:* ${eng.startDate}`,
    emailSubject: `New engagement: ${eng.clientName} (${eng.company})`,
    emailBody:    `A new engagement has been created in Barinhall Delivery Hub.\n\nClient: ${eng.clientName}\nCompany: ${eng.company}\nService: ${eng.serviceType}\nOwner: ${eng.owner}\nStart Date: ${eng.startDate}\nStatus: ${eng.status}`
  }
}];
